style.scss:
$warm-glow: rgba(254, 128, 25, 0.11);
$forest-glow: rgba(184, 187, 38, 0.08);

body.theme-gruvbox-workshop {
  background-image:
    radial-gradient(circle at top left, $warm-glow, transparent 34%),
    radial-gradient(circle at top right, $forest-glow, transparent 28%),
    linear-gradient(180deg, rgba(60, 56, 54, 0.68), rgba(40, 40, 40, 0.92));

  .mode-panel,
  .panel,
  .modal {
    box-shadow: none;
  }

  .btn-accent {
    text-transform: uppercase;
    letter-spacing: 0.04em;
  }

  .page-title,
  h1,
  h2,
  h3 {
    letter-spacing: 0.02em;
  }
}

